head.b:skin:
:root {
  --yellow: #FFD93D;
  --blue: #6BCBFF;
  --coral: #FF6B6B;
  --purple: #B28DFF;
  --green: #6EE7B7;
  --dark: #2D3436;
  --gray: #636e72;
  --light: #FFF8E7;
  --white: #FFFFFF;
  --shadow-sm: 0 2px 8px rgba(0,0,0,0.08);
  --shadow: 0 4px 20px rgba(0,0,0,0.1);
  --shadow-lg: 0 8px 40px rgba(0,0,0,0.15);
  --radius-sm: 10px;
  --radius: 16px;
  --radius-lg: 24px;
  --radius-xl: 32px;
  --font-display: 'Baloo 2', cursive;
  --font-rounded: 'Fredoka', sans-serif;
  --font-body: 'Nunito', sans-serif;
  --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  --bounce: cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth;overflow-x:hidden}
body{font-family:var(--font-body);background:var(--white);color:var(--dark);line-height:1.6;overflow-x:hidden;-webkit-font-smoothing:antialiased;padding-top:70px}
img{max-width:100%;height:auto;display:block}
a{text-decoration:none;color:inherit}
ul{list-style:none}
.container{max-width:1200px;margin:0 auto;padding:0 clamp(15px, 3vw, 25px)}
.section{display:block;opacity:1;width:100%}
.section-title{font-family:var(--font-display);font-size:clamp(1.4rem, 4.5vw, 2.2rem);text-align:center;margin-bottom:clamp(20px, 4vw, 40px);color:var(--dark);position:relative;padding-bottom:15px}
.section-title::after{content:'';position:absolute;bottom:0;left:50%;transform:translateX(-50%);width:80px;height:4px;border-radius:2px;background:linear-gradient(90deg,var(--coral),var(--yellow));opacity:0.8}

@keyframes float{0%,100%{transform:translateY(0) rotate(0deg)}50%{transform:translateY(-20px) rotate(3deg)}}
@keyframes twinkle{0%,100%{opacity:1}50%{opacity:0.3}}
@keyframes pulse{0%,100%{transform:scale(1)}50%{transform:scale(1.05)}}
@keyframes bounceIn{0%{transform:scale(0);opacity:0}60%{transform:scale(1.1)}100%{transform:scale(1);opacity:1}}
@keyframes wiggle{0%,100%{transform:rotate(0deg)}25%{transform:rotate(-5deg)}75%{transform:rotate(5deg)}}
@keyframes slideUp{0%{transform:translateY(40px);opacity:0}100%{transform:translateY(0);opacity:1}}
@keyframes scaleIn{0%{transform:scale(0.8);opacity:0}100%{transform:scale(1);opacity:1}}
@keyframes fadeIn{0%{opacity:0}100%{opacity:1}}

body.js-active .fade-in{opacity:0;transform:translateY(30px);transition:opacity 0.6s ease,transform 0.6s ease}
body.js-active .fade-in.visible{opacity:1;transform:translateY(0)}
body.js-active .fade-in-scale{opacity:0;transform:scale(0.8);transition:opacity 0.5s ease,transform 0.5s var(--bounce)}
body.js-active .fade-in-scale.visible{opacity:1;transform:scale(1)}

.card{background:var(--white);border-radius:var(--radius);box-shadow:var(--shadow);overflow:hidden;transition:var(--transition)}
@media(hover:hover){.card:hover{transform:translateY(-5px);box-shadow:var(--shadow-lg)}}

header{position:fixed;top:0;left:0;width:100%;z-index:9999;padding:15px 0;transition:var(--transition);background:rgba(255,255,255,0.85);backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px)}
header.scrolled{box-shadow:0 2px 20px rgba(0,0,0,0.1);padding:8px 0}
.header-inner{display:flex;align-items:center;justify-content:space-between;max-width:1200px;margin:0 auto;padding:0 20px}
.header-logo{display:flex;align-items:center;gap:10px;font-family:var(--font-display);font-size:clamp(1.2rem, 3vw, 1.5rem);font-weight:800;color:var(--coral);cursor:pointer;transition:var(--transition)}
.header-logo:hover{animation:wiggle 0.5s ease}
.header-logo span{font-size:1.8rem}
.header-nav{display:flex;gap:5px;align-items:center}
.header-nav a{padding:8px 16px;border-radius:50px;font-family:var(--font-rounded);font-size:0.95rem;font-weight:500;color:var(--dark);transition:var(--transition);display:inline-block}
.header-nav a:hover,.header-nav a.active{background:linear-gradient(135deg,var(--coral),var(--purple));color:#fff;box-shadow:0 4px 15px rgba(255,107,107,0.3)}
.header-actions{display:flex;align-items:center;gap:10px}
.header-search-btn,.header-menu-btn{background:none;border:none;font-size:1.2rem;color:var(--dark);padding:10px;cursor:pointer;border-radius:50%;transition:var(--transition)}
.header-search-btn:hover{background:rgba(107,203,255,0.15);color:var(--blue);transform:scale(1.1)}
.header-menu-btn{display:none;font-size:1.5rem}
.header-menu-btn:hover{background:rgba(255,107,107,0.15);color:var(--coral)}
.mobile-dropdown{position:absolute;top:100%;left:0;width:100%;background:var(--white);box-shadow:0 10px 25px rgba(0,0,0,0.1);border-bottom:3px solid var(--purple);overflow:hidden;max-height:0;transition:max-height 0.3s ease}
.mobile-dropdown.active{max-height:80vh;overflow-y:auto}
.mobile-nav{display:flex;flex-direction:column;padding:15px 20px;gap:5px}
.mobile-nav a{display:flex;align-items:center;gap:15px;padding:12px 18px;border-radius:var(--radius-sm);font-family:var(--font-rounded);font-size:1rem;font-weight:500;color:var(--dark);transition:var(--transition)}
.mobile-nav a:hover,.mobile-nav a.active{background:linear-gradient(135deg,var(--coral),var(--purple));color:#fff}

#secHero{padding:clamp(100px,12vw,140px) 0 clamp(60px,8vw,80px);background:linear-gradient(135deg,#FFD93D,#FF6B6B,#B28DFF,#6BCBFF);background-size:400% 400%;position:relative;overflow:hidden;margin-top:0}
#secHero::before{content:'';position:absolute;top:-50%;right:-50%;width:500px;height:500px;background:rgba(255,255,255,0.1);border-radius:50%;animation:float 15s ease-in-out infinite}
#secHero::after{content:'';position:absolute;bottom:-30%;left:-30%;width:300px;height:300px;background:rgba(0,0,0,0.05);border-radius:50%;animation:float 20s ease-in-out infinite reverse}
.hero-content{position:relative;z-index:2;text-align:center;color:#fff;max-width:800px;margin:0 auto;padding:0 clamp(15px,3vw,25px)}
.hero-title{font-family:var(--font-display);font-size:clamp(1.8rem,6vw,3.5rem);font-weight:800;margin-bottom:20px;animation:bounceIn 1s var(--bounce);text-shadow:0 4px 15px rgba(0,0,0,0.2);line-height:1.2}
.hero-subtitle{font-family:var(--font-body);font-size:clamp(0.95rem,2.5vw,1.25rem);margin-bottom:clamp(20px,4vw,40px);animation:slideUp 0.8s ease forwards;animation-delay:0.5s;text-shadow:0 2px 8px rgba(0,0,0,0.1);opacity:0.95}
.hero-cta{display:flex;gap:20px;justify-content:center;flex-wrap:wrap;animation:slideUp 0.8s ease forwards;animation-delay:0.8s}
.btn-primary{padding:16px 40px;border:none;border-radius:50px;font-family:var(--font-display);font-size:1.1rem;font-weight:700;cursor:pointer;transition:var(--transition);display:inline-flex;align-items:center;gap:8px;background:linear-gradient(135deg,var(--coral),#FF8A5C);color:#fff;box-shadow:0 4px 20px rgba(255,107,107,0.4);text-decoration:none}
@media(hover:hover){.btn-primary:hover{transform:translateY(-3px);box-shadow:0 8px 30px rgba(255,107,107,0.6)}}
.btn-primary:focus{outline:2px solid rgba(255,255,255,0.5);outline-offset:2px}
.btn-secondary{padding:16px 40px;border:none;border-radius:50px;font-family:var(--font-display);font-size:1.1rem;font-weight:700;cursor:pointer;transition:var(--transition);display:inline-flex;align-items:center;gap:8px;background:#fff;color:var(--coral);box-shadow:0 4px 20px rgba(255,255,255,0.4);text-decoration:none}
@media(hover:hover){.btn-secondary:hover{transform:translateY(-3px);box-shadow:0 8px 30px rgba(255,217,61,0.7)}}
.btn-secondary:focus{outline:2px solid rgba(255,107,107,0.5);outline-offset:2px}

#secCategories,#secShorts,#secTrust,#secSubscribe,#secBlog,#secGameCenter{padding:clamp(40px,6vw,60px) 0;width:100%}
#secCategories{background:var(--light)}

.categories-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:clamp(15px,2.5vw,25px)}
.category-card{display:block;border-radius:var(--radius);padding:clamp(20px,3.5vw,35px) clamp(15px,2.5vw,25px);text-align:center;cursor:pointer;transition:var(--transition);box-shadow:var(--shadow);color:#fff;text-decoration:none}
@media(hover:hover){.category-card:hover{transform:translateY(-8px);box-shadow:var(--shadow-lg)}}
.category-card .cat-emoji{font-size:clamp(2.2rem,5vw,3.5rem);margin-bottom:15px;display:block}
.category-card .cat-name{font-family:var(--font-display);font-size:clamp(1.1rem,2.5vw,1.4rem);font-weight:700;margin-bottom:8px}
.category-card .cat-link{font-family:var(--font-rounded);font-size:0.9rem;display:inline-flex;align-items:center;gap:5px;transition:var(--transition);text-decoration:none;color:inherit}
@media(hover:hover){.category-card:hover .cat-link{gap:10px}}
.cat-abc{background:linear-gradient(135deg,#FF6B6B,#ee5a24)}
.cat-123{background:linear-gradient(135deg,#6BCBFF,#0984e3)}
.cat-colors{background:linear-gradient(135deg,#B28DFF,#6c5ce7)}
.cat-animals{background:linear-gradient(135deg,#6EE7B7,#00b894)}
.cat-hindi{background:linear-gradient(135deg,#FFD93D,#fdcb6e)}
.cat-songs{background:linear-gradient(135deg,#FF8A5C,#e17055)}
.cat-body{background:linear-gradient(135deg,#74b9ff,#0984e3)}
.cat-food{background:linear-gradient(135deg,#55efc4,#00b894)}
.cat-vehicles{background:linear-gradient(135deg,#a29bfe,#6c5ce7)}
.cat-world{background:linear-gradient(135deg,#fd79a8,#e84393)}
.cat-habits{background:linear-gradient(135deg,#ffeaa7,#fdcb6e);color:#2D3436}

#secSubscribe{background:linear-gradient(135deg,var(--coral),#FF8A5C);position:relative;overflow:hidden;text-align:center}
#secSubscribe::before{content:'';position:absolute;top:-50%;right:-20%;width:400px;height:400px;background:rgba(255,255,255,0.1);border-radius:50%;animation:float 20s ease-in-out infinite}
.subscribe-inner{position:relative;z-index:2;max-width:700px;margin:0 auto;padding:0 20px}
.subscribe-inner h2{font-family:var(--font-display);font-size:2.5rem;color:#fff;margin-bottom:15px}
.subscribe-inner p{font-family:var(--font-body);font-size:1.1rem;color:rgba(255,255,255,0.9);margin-bottom:35px}
.subscribe-btn{display:inline-flex;align-items:center;gap:12px;padding:18px 45px;background:#fff;border:none;border-radius:50px;font-family:var(--font-display);font-size:1.15rem;font-weight:700;color:var(--coral);cursor:pointer;transition:var(--transition);box-shadow:0 4px 20px rgba(0,0,0,0.2);text-decoration:none}
.subscribe-btn:focus{outline:2px solid rgba(255,255,255,0.5);outline-offset:2px}
@media(hover:hover){.subscribe-btn:hover{transform:translateY(-3px);box-shadow:0 8px 30px rgba(0,0,0,0.25)}}

main{width:100%}
#secBlog{background:var(--white);padding:clamp(40px,6vw,60px) 0;width:100%}
.blog-posts-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:30px}
.blog-post-card{background:var(--white);border-radius:var(--radius);overflow:hidden;box-shadow:var(--shadow);transition:var(--transition)}
@media(hover:hover){.blog-post-card:hover{transform:translateY(-5px);box-shadow:var(--shadow-lg)}}
.post-featured-img{width:100%;height:220px;object-fit:cover}
.post-gradient-placeholder{width:100%;height:220px;display:flex;align-items:center;justify-content:center;font-size:3rem;background:var(--light)}
.post-content{padding:22px 25px}
.post-content h3{font-family:var(--font-display);font-size:1.3rem;font-weight:700;margin-bottom:10px;color:var(--dark);line-height:1.3}
.post-content h3 a{transition:var(--transition);text-decoration:none;color:inherit}
.post-content h3 a:hover{color:var(--coral)}
.post-meta{font-family:var(--font-body);font-size:0.85rem;color:var(--gray);margin-bottom:12px;display:flex;align-items:center;gap:15px;flex-wrap:wrap}
.post-snippet{font-family:var(--font-body);font-size:0.95rem;color:var(--gray);line-height:1.6;margin-bottom:15px}
.post-labels{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:15px}
.post-labels a{padding:4px 14px;background:var(--light);border-radius:50px;font-size:0.8rem;font-family:var(--font-rounded);color:var(--gray);transition:var(--transition);text-decoration:none;display:inline-block}
.post-labels a:hover{background:var(--coral);color:#fff}
.blog-pagination{display:flex;justify-content:center;gap:15px;margin-top:40px}
.blog-pagination a,.blog-pagination span{padding:12px 30px;background:var(--light);border-radius:50px;font-family:var(--font-rounded);font-weight:600;transition:var(--transition);color:var(--dark);text-decoration:none;display:inline-block}
.blog-pagination a:hover{background:var(--coral);color:#fff;box-shadow:0 4px 15px rgba(255,107,107,0.3)}
.read-more-link{display:inline-flex;align-items:center;gap:6px;margin-top:12px;font-family:var(--font-rounded);font-size:0.9rem;font-weight:700;color:var(--coral);transition:var(--transition);text-decoration:none}
.read-more-link:hover{gap:10px;color:var(--purple)}

#secSingle{background:var(--white);padding:clamp(100px,8vw,130px) 0 clamp(40px,6vw,60px);min-height:70vh;width:100%}
.single-post{max-width:800px;margin:0 auto;padding:0 20px}
.single-post .post-featured-img{width:100%;height:auto;max-height:500px;object-fit:cover;border-radius:var(--radius);margin-bottom:30px}
.single-post h1,.single-post .post-title{font-family:var(--font-display);font-size:2.2rem;font-weight:800;margin-bottom:15px;color:var(--dark);line-height:1.3}
.single-post .post-meta{margin-bottom:20px;font-size:0.95rem;color:var(--gray);display:flex;gap:20px;flex-wrap:wrap}
.single-post .post-meta span{display:flex;align-items:center;gap:6px}
.single-post .post-body{font-family:var(--font-body);font-size:1.05rem;line-height:1.8;color:var(--dark)}
.single-post .post-body h2,.single-post .post-body h3,.single-post .post-body h4{font-family:var(--font-display);margin:30px 0 15px;color:var(--dark)}
.single-post .post-body h2{font-size:1.8rem;border-bottom:2px solid var(--light);padding-bottom:10px}
.single-post .post-body h3{font-size:1.5rem;color:var(--coral)}
.single-post .post-body h4{font-size:1.2rem}
.single-post .post-body p{margin-bottom:18px;line-height:1.8}
.single-post .post-body a{color:var(--blue);text-decoration:none;font-weight:600}
.single-post .post-body a:hover{text-decoration:underline}
.single-post .post-body img{max-width:100%;height:auto;border-radius:var(--radius-sm);margin:20px 0;display:block;box-shadow:var(--shadow-sm)}
.single-post .post-body ul,.single-post .post-body ol{margin:0 0 20px 20px;padding-left:20px}
.single-post .post-body ul li,.single-post .post-body ol li{margin-bottom:10px;line-height:1.6}
.single-post .post-body blockquote{margin:20px 0;padding:15px 25px;border-left:5px solid var(--purple);background:var(--light);border-radius:0 var(--radius-sm) var(--radius-sm) 0;font-style:italic;color:var(--gray)}
.single-post .post-body code{font-family:monospace;background:#f4f4f4;padding:2px 6px;border-radius:4px;font-size:0.9em;color:var(--coral)}
.single-post .post-body pre{background:#282c34;color:#abb2bf;padding:15px;border-radius:var(--radius-sm);overflow-x:auto;margin:20px 0;line-height:1.4}
.single-post .post-body pre code{background:transparent;color:inherit;padding:0}
.single-post .post-body table{width:100%;border-collapse:collapse;margin:20px 0}
.single-post .post-body th,.single-post .post-body td{border:1px solid #eee;padding:12px 15px;text-align:left}
.single-post .post-body th{background:var(--light);font-family:var(--font-rounded);color:var(--dark);font-weight:600}
.single-post .post-body tr:nth-child(even){background:#fafafa}
.post-nav{display:flex;justify-content:space-between;gap:20px;margin-top:50px;padding-top:30px;border-top:1px solid #eee}
.post-nav a{flex:1;padding:20px;background:var(--light);border-radius:var(--radius);transition:var(--transition);font-family:var(--font-rounded);font-size:0.95rem;color:var(--dark);text-decoration:none}
.post-nav a:focus{outline:2px solid var(--coral);outline-offset:2px}
@media(hover:hover){.post-nav a:hover{background:var(--coral);color:#fff}}
.post-nav .prev{text-align:left}
.post-nav .next{text-align:right}
.post-nav .nav-label{display:block;font-size:0.8rem;color:var(--gray);margin-bottom:5px}
@media(hover:hover){.post-nav a:hover .nav-label{color:rgba(255,255,255,0.7)}}

.labels-section{margin-top:40px;padding-top:20px;border-top:1px solid #eee}
.post-labels-title{font-family:var(--font-rounded);font-size:0.9rem;font-weight:600;color:var(--gray);text-transform:uppercase;margin-bottom:10px;letter-spacing:0.5px}
.post-labels-list{display:flex;flex-wrap:wrap;gap:8px}
.post-labels-list a{padding:6px 16px;background:var(--coral);color:#fff;border-radius:50px;font-size:0.85rem;font-family:var(--font-rounded);font-weight:600;transition:var(--transition);text-decoration:none;display:inline-block}
.post-labels-list a:focus{outline:2px solid var(--dark);outline-offset:2px}
@media(hover:hover){.post-labels-list a:hover{background:var(--purple);box-shadow:var(--shadow)}}

.comments-wrapper{margin-top:50px;padding-top:30px;border-top:1px solid #eee;width:100%}
.comments-title{font-family:var(--font-display);font-size:1.5rem;color:var(--dark);margin-bottom:20px}
.comments-list{display:flex;flex-direction:column;gap:15px}
.comment-item{background:var(--light);border-radius:var(--radius-sm);padding:15px;margin-bottom:0}
.comment-author{font-family:var(--font-rounded);font-weight:600;color:var(--dark);margin-bottom:5px}
.comment-date{font-size:0.85rem;color:var(--gray);margin-bottom:10px}
.comment-body{font-family:var(--font-body);color:var(--dark);line-height:1.6;word-wrap:break-word}

#secSearchResults{background:var(--white);padding:clamp(100px,8vw,120px) 0 clamp(40px,6vw,60px);min-height:70vh;width:100%}
.search-results-header{text-align:center;margin-bottom:40px}
.search-results-header h2{font-family:var(--font-display);font-size:1.8rem;color:var(--dark);margin-bottom:10px;word-wrap:break-word}
.search-results-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:30px;margin-bottom:40px}
.no-results{text-align:center;padding:60px 20px}
.no-results-icon{font-size:4rem;margin-bottom:20px;display:block;opacity:0.5}
.no-results h3{font-family:var(--font-display);font-size:1.5rem;margin-bottom:15px;color:var(--dark)}
.no-results p{font-family:var(--font-body);color:var(--gray);margin-bottom:25px}

footer{background:linear-gradient(135deg,#2D3436,#1a1a2e);padding:60px 0 30px;color:rgba(255,255,255,0.85);width:100%}
.footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:40px;margin-bottom:40px}
.footer-brand .footer-logo{font-family:var(--font-display);font-size:1.5rem;font-weight:800;color:#fff;margin-bottom:15px;display:flex;align-items:center;gap:10px}
.footer-brand .footer-logo span{font-size:1.8rem}
.footer-brand p{font-family:var(--font-body);font-size:0.9rem;line-height:1.7;margin-bottom:20px;color:rgba(255,255,255,0.6)}
.footer-social{display:flex;gap:12px}
.footer-social a{width:40px;height:40px;border-radius:50%;background:rgba(255,255,255,0.1);display:flex;align-items:center;justify-content:center;color:#fff;font-size:1.1rem;transition:var(--transition);text-decoration:none;outline:2px solid transparent}
.footer-social a:focus{outline:2px solid #fff;outline-offset:2px}
@media(hover:hover){.footer-social a:hover{transform:translateY(-3px);background:rgba(255,255,255,0.2)}}
.footer-col h4{font-family:var(--font-display);font-size:1.1rem;font-weight:700;color:#fff;margin-bottom:20px;position:relative;padding-bottom:10px}
.footer-col h4::after{content:'';position:absolute;bottom:0;left:0;width:30px;height:3px;background:var(--coral);border-radius:2px}
.footer-col ul li{margin-bottom:10px}
.footer-col ul li a{font-family:var(--font-body);font-size:0.9rem;color:rgba(255,255,255,0.6);transition:var(--transition);text-decoration:none;display:block;padding:5px 0}
.footer-col ul li a:focus{outline:2px solid #fff;outline-offset:2px}
@media(hover:hover){.footer-col ul li a:hover{color:var(--coral)}}
.footer-bottom{text-align:center;padding-top:25px;border-top:1px solid rgba(255,255,255,0.1);font-family:var(--font-body);font-size:0.85rem;color:rgba(255,255,255,0.5)}
.footer-bottom a{color:var(--coral);transition:var(--transition);text-decoration:none}
.footer-bottom a:focus{outline:2px solid #fff;outline-offset:2px}
@media(hover:hover){.footer-bottom a:hover{color:var(--yellow)}}

#homepageSections{display:none;width:100%}
body.is-homepage #homepageSections{display:block}
body.is-homepage #secBlog{padding-top:0}

.breadcrumb{font-family:var(--font-rounded);font-size:0.9rem;color:var(--gray);margin-bottom:20px;display:flex;flex-wrap:wrap;gap:8px;align-items:center}
.breadcrumb a{color:var(--blue);text-decoration:none}
.breadcrumb a:hover{text-decoration:underline}
.breadcrumb::before{content:'🏠';margin-right:5px}

.archive-title{font-family:var(--font-display);font-size:2rem;color:var(--dark);margin-bottom:30px}

.search-overlay{position:fixed;inset:0;background:rgba(45,52,54,0.78);z-index:10000;display:flex;align-items:flex-start;justify-content:center;padding:90px 18px 30px;opacity:0;visibility:hidden;transition:var(--transition);backdrop-filter:blur(8px)}
.search-overlay.active{opacity:1;visibility:visible}
.search-panel{width:min(760px,100%);background:#fff;border-radius:var(--radius-lg);box-shadow:var(--shadow-lg);padding:clamp(20px,4vw,35px);position:relative;animation:scaleIn .25s var(--bounce)}
.search-close{position:absolute;top:14px;right:14px;width:42px;height:42px;border:0;border-radius:50%;background:var(--light);color:var(--dark);font-size:1.1rem;cursor:pointer;transition:var(--transition)}
.search-close:hover,.search-close:focus{background:var(--coral);color:#fff;outline:2px solid var(--purple);outline-offset:2px}
.search-panel h2{font-family:var(--font-display);font-size:1.8rem;color:var(--dark);margin-bottom:16px;padding-right:45px}
.search-form{display:flex;gap:12px;align-items:center}
.search-form input{flex:1;min-width:0;padding:16px 18px;border:2px solid #eee;border-radius:50px;font-family:var(--font-body);font-size:1rem;outline:none;transition:var(--transition)}
.search-form input:focus{border-color:var(--coral);box-shadow:0 0 0 4px rgba(255,107,107,.12)}
.share-section{margin:28px 0;padding:20px;background:linear-gradient(135deg,#fff8e7,#fff);border-radius:var(--radius);border:1px solid #f2ead4}
.share-title,.related-title{font-family:var(--font-display);font-size:1.25rem;color:var(--dark);margin-bottom:14px}
.share-buttons{display:flex;flex-wrap:wrap;gap:10px}
.share-btn{border:0;border-radius:50px;padding:10px 16px;font-family:var(--font-rounded);font-weight:600;color:#fff;cursor:pointer;display:inline-flex;gap:8px;align-items:center;transition:var(--transition)}
.share-btn:hover,.share-btn:focus{transform:translateY(-2px);box-shadow:var(--shadow);outline:2px solid rgba(0,0,0,.1);outline-offset:2px}
.share-facebook{background:#1877f2}.share-x{background:#111}.share-whatsapp{background:#25d366}.share-pinterest{background:#bd081c}.share-copy{background:var(--purple)}
.reading-progress{position:fixed;top:0;left:0;width:0;height:4px;background:linear-gradient(90deg,var(--yellow),var(--coral),var(--purple));z-index:10001;transition:width .1s linear}
.related-posts{margin-top:45px;padding-top:28px;border-top:1px solid #eee}
.related-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}
.related-card{display:block;background:var(--white);border-radius:var(--radius-sm);overflow:hidden;box-shadow:var(--shadow-sm);transition:var(--transition);border:1px solid #f1f1f1}
.related-card:hover,.related-card:focus{transform:translateY(-3px);box-shadow:var(--shadow);outline:2px solid var(--coral);outline-offset:2px}
.related-card img{width:100%;height:110px;object-fit:cover;background:var(--light)}
.related-card span{display:block;padding:12px;font-family:var(--font-rounded);font-weight:600;font-size:.92rem;color:var(--dark);line-height:1.35}
.related-empty{font-family:var(--font-body);color:var(--gray);background:var(--light);border-radius:var(--radius-sm);padding:14px}
.post-body iframe,.post-body embed,.post-body object{max-width:100%;border:0;border-radius:var(--radius-sm);box-shadow:var(--shadow-sm)}
.post-body iframe[src*="youtube"],.post-body iframe[src*="vimeo"]{width:100%;aspect-ratio:16/9;height:auto}
.updated-meta,.reading-time{display:inline-flex;align-items:center;gap:6px}
.contact-card{margin:35px 0;padding:25px;background:linear-gradient(135deg,var(--light),#fff);border-radius:var(--radius);box-shadow:var(--shadow-sm);border:1px solid #f3ecd6}
.contact-actions{display:flex;flex-wrap:wrap;gap:12px;margin-top:15px}
.contact-actions a{display:inline-flex;align-items:center;gap:8px;padding:12px 18px;border-radius:50px;background:var(--coral);color:#fff!important;font-family:var(--font-rounded);font-weight:700;text-decoration:none!important}
.contact-actions a:nth-child(2){background:var(--purple)}
.error-page{min-height:65vh;padding:clamp(110px,10vw,150px) 20px 70px;text-align:center;background:var(--white)}
.error-page h1{font-family:var(--font-display);font-size:clamp(3rem,12vw,7rem);color:var(--coral);line-height:1}
.error-page h2{font-family:var(--font-display);font-size:2rem;color:var(--dark);margin:15px 0}
.error-page p{color:var(--gray);margin-bottom:25px}
.contact-widget-shell{display:none;max-width:800px;margin:0 auto 60px;padding:0 20px}.contact-page .contact-widget-shell{display:block}.contact-widget-shell .widget{background:#fff;border-radius:var(--radius);box-shadow:var(--shadow);padding:24px}.contact-widget-shell h2,.contact-widget-shell h3{font-family:var(--font-display);color:var(--dark);margin-bottom:15px}.sidebar-widgets{display:none}
@media(max-width:768px){.search-form{flex-direction:column}.search-form .btn-primary{width:100%;justify-content:center}.related-grid{grid-template-columns:1fr}.share-buttons{display:grid;grid-template-columns:1fr 1fr}.share-btn{justify-content:center}.single-post .post-body table{display:block;overflow-x:auto;white-space:nowrap}}

@media(max-width:992px){
  .header-nav{display:none}
  .header-menu-btn{display:block}
  .categories-grid{grid-template-columns:repeat(2,1fr)}
  .footer-grid{grid-template-columns:1fr 1fr;gap:30px}
  .blog-posts-grid{grid-template-columns:1fr}
  .search-results-grid{grid-template-columns:1fr}
}
@media(max-width:768px){
  body{padding-top:60px}
  .blog-posts-grid{grid-template-columns:1fr}
  .search-results-grid{grid-template-columns:1fr}
  .footer-grid{grid-template-columns:1fr 1fr;gap:25px}
  .post-nav{flex-direction:column}
  .single-post h1{font-size:1.6rem}
  .hero-title{font-size:2.2rem}
  .categories-grid{grid-template-columns:repeat(2,1fr)}
}
@media(max-width:480px){
  .categories-grid{grid-template-columns:1fr}
  .footer-grid{grid-template-columns:1fr}
  .btn-primary,.btn-secondary{padding:14px 30px;font-size:1rem}
  .hero-title{font-size:1.8rem}
  .single-post h1{font-size:1.4rem}
  .subscribe-inner h2{font-size:1.8rem}
}

body.script:

(function() {
  'use strict';

  // Header scroll effect
  window.addEventListener('scroll', function() {
    var header = document.querySelector('header');
    if (window.scrollY > 50) {
      header.classList.add('scrolled');
    } else {
      header.classList.remove('scrolled');
    }
  });

  // Mobile menu toggle
  var menuBtn = document.getElementById('menuBtn');
  var dropdown = document.getElementById('mobileDropdown');
  if (menuBtn && dropdown) {
    menuBtn.addEventListener('click', function(e) {
      e.preventDefault();
      dropdown.classList.toggle('active');
      dropdown.setAttribute('aria-hidden', dropdown.classList.contains('active') ? 'false' : 'true');
    });

    // Close menu when clicking on mobile nav links
    var mobileLinks = dropdown.querySelectorAll('a');
    mobileLinks.forEach(function(link) {
      link.addEventListener('click', function() {
        dropdown.classList.remove('active');
        dropdown.setAttribute('aria-hidden', 'true');
      });
    });

    // Close menu when clicking outside
    document.addEventListener('click', function(e) {
      if (!menuBtn.contains(e.target) && !dropdown.contains(e.target)) {
        dropdown.classList.remove('active');
        dropdown.setAttribute('aria-hidden', 'true');
      }
    });
  }

  // Update year in footer
  var yearElement = document.getElementById('year');
  if (yearElement) {
    yearElement.textContent = new Date().getFullYear();
  }

  // Contact page helper for the Blogger ContactForm widget
  if (window.location.pathname === '/p/contact.html') {
    document.body.classList.add('contact-page');
  }

  // Blogger search overlay
  var searchBtn = document.getElementById('searchBtn');
  var searchOverlay = document.getElementById('searchOverlay');
  var searchClose = document.getElementById('searchClose');
  var searchInput = document.getElementById('searchInput');
  function openSearch() {
    if (!searchOverlay) { return; }
    searchOverlay.classList.add('active');
    searchOverlay.setAttribute('aria-hidden', 'false');
    if (searchInput) { window.setTimeout(function(){ searchInput.focus(); }, 80); }
  }
  function closeSearch() {
    if (!searchOverlay) { return; }
    searchOverlay.classList.remove('active');
    searchOverlay.setAttribute('aria-hidden', 'true');
    if (searchBtn) { searchBtn.focus(); }
  }
  if (searchBtn) {
    searchBtn.addEventListener('click', function(e) {
      e.preventDefault();
      openSearch();
    });
  }
  if (searchClose) { searchClose.addEventListener('click', closeSearch); }
  if (searchOverlay) {
    searchOverlay.addEventListener('click', function(e) {
      if (e.target === searchOverlay) { closeSearch(); }
    });
  }
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') { closeSearch(); }
  });

  // Reading progress and estimated reading time
  var article = document.querySelector('.single-post-article');
  if (article) {
    var progress = document.createElement('div');
    progress.className = 'reading-progress';
    document.body.appendChild(progress);
    var bodyText = article.querySelector('.post-body');
    var words = bodyText ? (bodyText.textContent || '').trim().split(/\s+/).filter(Boolean).length : 0;
    var minutes = Math.max(1, Math.ceil(words / 180));
    var readingValue = article.querySelector('.reading-time-value');
    if (readingValue) { readingValue.textContent = minutes + ' min read'; }
    window.addEventListener('scroll', function() {
      var rect = article.getBoundingClientRect();
      var total = Math.max(1, article.offsetHeight - window.innerHeight);
      var passed = Math.min(Math.max(-rect.top, 0), total);
      progress.style.width = ((passed / total) * 100) + '%';
    }, {passive:true});
  }

  // Share buttons
  var shareButtons = document.querySelectorAll('[data-share]');
  shareButtons.forEach(function(btn) {
    btn.addEventListener('click', function() {
      var url = window.location.href;
      var title = document.title;
      var type = btn.getAttribute('data-share');
      var shareUrl = '';
      if (type === 'facebook') { shareUrl = 'https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(url); }
      if (type === 'x') { shareUrl = 'https://twitter.com/intent/tweet?url=' + encodeURIComponent(url) + '&text=' + encodeURIComponent(title); }
      if (type === 'whatsapp') { shareUrl = 'https://api.whatsapp.com/send?text=' + encodeURIComponent(title + ' ' + url); }
      if (type === 'pinterest') { shareUrl = 'https://pinterest.com/pin/create/button/?url=' + encodeURIComponent(url) + '&description=' + encodeURIComponent(title); }
      if (type === 'copy') {
        if (navigator.clipboard) { navigator.clipboard.writeText(url); }
        btn.innerHTML = '<i class="fas fa-check" aria-hidden="true"></i> Copied';
        window.setTimeout(function(){ btn.innerHTML = '<i class="fas fa-link" aria-hidden="true"></i> Copy Link'; }, 1800);
        return;
      }
      if (shareUrl) { window.open(shareUrl, '_blank', 'noopener,noreferrer,width=700,height=520'); }
    });
  });

  // Dynamic related posts from first label, excluding current URL
  var relatedGrid = document.getElementById('relatedPosts');
  if (relatedGrid) {
    var firstLabel = document.querySelector('.related-label');
    if (firstLabel && firstLabel.textContent.trim()) {
      var feedUrl = 'https://pogotunes.blogspot.com/feeds/posts/default/-/' + encodeURIComponent(firstLabel.textContent.trim()) + '?alt=json&max-results=8';
      fetch(feedUrl).then(function(res){ return res.json(); }).then(function(data) {
        var entries = (data.feed && data.feed.entry) ? data.feed.entry : [];
        var current = window.location.href.replace(/[#?].*$/, '');
        var html = '';
        entries.forEach(function(entry) {
          if (html.split('related-card').length > 3) { return; }
          var link = (entry.link || []).filter(function(l){ return l.rel === 'alternate'; })[0];
          if (!link || link.href.replace(/[#?].*$/, '') === current) { return; }
          var title = entry.title ? entry.title.$t : 'Related post';
          var img = 'https://pogotunes.blogspot.com/favicon.ico';
          if (entry.media$thumbnail && entry.media$thumbnail.url) { img = entry.media$thumbnail.url.replace('/s72-c/', '/s320/'); }
          html += '<a class="related-card" href="' + link.href + '"><img alt="" loading="lazy" src="' + img + '"/><span>' + title + '</span></a>';
        });
        relatedGrid.innerHTML = html || '<p class="related-empty">More related learning posts will appear here soon.</p>';
      }).catch(function(){ relatedGrid.innerHTML = '<p class="related-empty">More related learning posts will appear here soon.</p>'; });
    } else {
      relatedGrid.innerHTML = '<p class="related-empty">More related learning posts will appear here soon.</p>';
    }
  }

  // Intersection Observer for fade-in animations
  if ('IntersectionObserver' in window) {
    var observer = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          entry.target.classList.add('visible');
          observer.unobserve(entry.target);
        }
      });
    }, {
      threshold: 0.1,
      rootMargin: '0px 0px -100px 0px'
    });

    var fadeElements = document.querySelectorAll('.fade-in, .fade-in-scale');
    fadeElements.forEach(function(el) {
      observer.observe(el);
    });
  }

  // Keyboard navigation for category cards
  var categoryCards = document.querySelectorAll('.category-card');
  categoryCards.forEach(function(card) {
    card.addEventListener('keypress', function(e) {
      if (e.key === 'Enter' || e.key === ' ') {
        e.preventDefault();
        card.click();
      }
    });
  });
})();
